function T(en,es){return state.lang==='es'?es:en;}
function statusLabel(s){return s==='delivered'?T('Delivered','Entregado'):s==='transit'?T('In Transit','En Tránsito'):T('Processing','Procesando');}
function statusClass(s){return s==='delivered'?'st-delivered':s==='transit'?'st-transit':'st-processing';}
const catColors={dairy:'#3b82f6',meat:'#ef4444',produce:'#22c55e',dry:'#f59e0b',supplies:'#8b5cf6'};
document.addEventListener('DOMContentLoaded',()=>{loadCart();renderProducts();updateCartCount();setupScroll();setupNav();initCountUp();initTicker();initTestimonials();formInit();});
function setupScroll(){const h=document.querySelector('.header');window.addEventListener('scroll',()=>h?.classList.toggle('scrolled',window.scrollY>40));const obs=new IntersectionObserver(e=>{e.forEach(x=>{if(x.isIntersecting)x.target.classList.add('visible')});},{threshold:0.08});document.querySelectorAll('.reveal').forEach(el=>obs.observe(el));}
function setupNav(){document.querySelectorAll('[data-nav]').forEach(el=>{el.addEventListener('click',e=>{e.preventDefault();const t=el.dataset.nav;if(t==='login')showLogin();else goTo(t);closeMobile();});});}
function goTo(id){showSite();setTimeout(()=>{const el=document.getElementById(id);if(el)el.scrollIntoView({behavior:'smooth',block:'start'});else window.scrollTo({top:0,behavior:'smooth'});},50);}
function showSite(){document.getElementById('main-site').style.display='';['page-login','page-dash-customer','page-dash-owner'].forEach(id=>document.getElementById(id)?.classList.remove('active'));document.querySelector('.header').style.display='';}
function showLogin(){document.getElementById('main-site').style.display='none';document.querySelector('.header').style.display='none';['page-dash-customer','page-dash-owner'].forEach(id=>document.getElementById(id)?.classList.remove('active'));document.getElementById('page-login').classList.add('active');window.scrollTo(0,0);}
function showDash(){document.getElementById('main-site').style.display='none';document.querySelector('.header').style.display='none';document.getElementById('page-login').classList.remove('active');if(state.role==='owner'){document.getElementById('page-dash-customer').classList.remove('active');document.getElementById('page-dash-owner').classList.add('active');renderOwnerSidebar();renderOwnerDash();}else{document.getElementById('page-dash-owner').classList.remove('active');document.getElementById('page-dash-customer').classList.add('active');renderCustTabs();renderCustDash();}window.scrollTo(0,0);}
function handleLogin(e){e.preventDefault();state.role=document.querySelector('.login-tab.active')?.dataset.role||'customer';state.loggedIn=true;showDash();renderProducts();}
function setLoginTab(role){document.querySelectorAll('.login-tab').forEach(t=>t.classList.toggle('active',t.dataset.role===role));const d=document.getElementById('demo-creds');d.innerHTML=role==='owner'?`<strong>${T('Owner Demo','Demo Admin')}</strong> — ${T('Email','Correo')}: owner@alamo.com / ${T('Password','Contraseña')}: demo`:`<strong>${T('Customer Demo','Demo Cliente')}</strong> — ${T('Email','Correo')}: demo@restaurant.com / ${T('Password','Contraseña')}: demo`;}
function logout(){state.loggedIn=false;state.role=null;showSite();renderProducts();window.scrollTo(0,0);}
function setLang(l){state.lang=l;document.querySelectorAll('.lang-toggle button').forEach(b=>b.classList.toggle('active',b.dataset.lang===l));document.querySelectorAll('[data-i18n]').forEach(el=>{const v=i18n[l]?.[el.dataset.i18n];if(v)el.innerHTML=v;});document.querySelectorAll('[data-i18n-ph]').forEach(el=>{const v=i18n[l]?.[el.dataset.i18nPh];if(v)el.placeholder=v;});renderProducts();renderCart();if(document.getElementById('page-dash-customer')?.classList.contains('active')){renderCustTabs();renderCustDash();}if(document.getElementById('page-dash-owner')?.classList.contains('active')){renderOwnerSidebar();renderOwnerDash();}const d=document.getElementById('demo-creds');if(d){setLoginTab(document.querySelector('.login-tab.active')?.dataset.role||'customer');}}
function initCountUp(){const obs=new IntersectionObserver(entries=>{entries.forEach(e=>{if(e.isIntersecting){const el=e.target,target=parseInt(el.dataset.target);let cur=0;const step=Math.ceil(target/40);const timer=setInterval(()=>{cur+=step;if(cur>=target){cur=target;clearInterval(timer);}el.textContent=cur+'+';},30);obs.unobserve(el);}});},{threshold:0.5});document.querySelectorAll('.count-up').forEach(el=>obs.observe(el));}
function updateSavings(val){const v=parseInt(val);document.getElementById('calc-spend').textContent='$'+v.toLocaleString();document.getElementById('calc-savings').textContent='$'+Math.round(v*0.15).toLocaleString();document.getElementById('calc-annual').textContent='$'+(Math.round(v*0.15)*12).toLocaleString();}
function initTicker(){const names=['Hacienda Bar & Grill','Zokalo','The Grove Taqueria','Fuego & Mar','Los Mariachis','Botanico','Mi Taco Taqueria','Santa Maria','Taqueria Norcross','The Golden Bite','Fuego Tortilla','Taqueria El Sol','La Paloma','El Rinconcito','Tacos El Patron'];const track=document.getElementById('ticker-track');if(!track)return;const html=names.map(n=>`<div class="ticker-item"><span class="ticker-dot"></span>${n}</div>`).join('');track.innerHTML=html+html;}
function initTestimonials(){const reviews=[{q:'"Alamo changed everything. We used to drive to Restaurant Depot at 6 AM. Now they deliver right to our door."',n:'Miguel R.',r:'Taqueria La Paloma, Norcross'},{q:'"Finally a distributor that speaks our language. I text my order in Spanish and it shows up next morning."',n:'Carmen S.',r:'El Rinconcito, Lawrenceville'},{q:'"Prices beat Restaurant Depot and I don\'t close my food truck for 3 hours to shop."',n:'Jorge L.',r:'Tacos El Patron, Marietta'},{q:'"No hidden fees, no price creep. The invoice matches the quote every time."',n:'Ana M.',r:'La Cocina de Ana, Canton'},{q:'"They understand our menu because they run their own restaurants."',n:'Roberto P.',r:'Taqueria Don Roberto, Norcross'},{q:'"Delivery drivers are professional. Product always cold and on time."',n:'Lucia F.',r:'El Sabor, Lawrenceville'}];const card=r=>`<div class="t-card"><div class="t-stars">★★★★★</div><blockquote>${r.q}</blockquote><div class="t-author"><div class="t-avatar">${r.n.split(' ').map(w=>w[0]).join('')}</div><div><div class="t-name">${r.n}</div><div class="t-role">${r.r}</div></div></div></div>`;const r1=document.getElementById('t-row-1'),r2=document.getElementById('t-row-2');if(!r1)return;const h1=reviews.slice(0,3).map(card).join(''),h2=reviews.slice(3).map(card).join('');r1.innerHTML=h1+h1+h1;r2.innerHTML=h2+h2+h2;}
function renderProducts(){const grid=document.getElementById('products-grid');if(!grid)return;let list=products.filter(p=>p.active);if(state.category!=='all')list=list.filter(p=>p.cat===state.category);if(state.search){const q=state.search.toLowerCase();list=list.filter(p=>p.name.toLowerCase().includes(q)||p.nameEs.toLowerCase().includes(q));}grid.innerHTML=list.length?list.map(p=>`<div class="product-card" onclick="openProductModal(${p.id})"><div class="p-img" style="background:${catColors[p.cat]||'#999'}15"><div class="p-img-icon" style="color:${catColors[p.cat]||'#999'}">${p.cat[0].toUpperCase()}</div>${p.badge?`<span class="p-badge badge-${p.badge}">${p.badge}</span>`:''}</div><div class="p-body"><div class="p-cat">${p.cat}</div><div class="p-name">${state.lang==='es'?p.nameEs:p.name}</div><div class="p-desc">${state.lang==='es'?p.descEs:p.desc}</div><div class="p-foot">${state.loggedIn?`<div class="p-price">$${p.price.toFixed(2)}<span class="p-unit">${p.unit}</span></div><button class="p-add" onclick="event.stopPropagation();addToCart(${p.id})">+</button>`:`<div class="p-locked">${i18n[state.lang]?.['p.locked']}</div><button class="btn btn-sm btn-outline" onclick="event.stopPropagation();showLogin()">${i18n[state.lang]?.['nav.signin']}</button>`}</div></div></div>`).join(''):'<p style="text-align:center;padding:40px;color:var(--gray-400)">No products found</p>';}
function filterCat(cat){state.category=cat;document.querySelectorAll('.catalog-tab').forEach(t=>t.classList.toggle('active',t.dataset.cat===cat));renderProducts();}
function searchProducts(v){state.search=v;renderProducts();}
function openProductModal(id){const p=products.find(x=>x.id===id);if(!p)return;const c=document.getElementById('pm-card');c.innerHTML=`<button class="pm-close" onclick="closeProductModal()">&#10005;</button><div class="pm-img" style="background:${catColors[p.cat]}15"><div class="p-img-icon" style="color:${catColors[p.cat]};font-size:4rem">${p.cat[0].toUpperCase()}</div></div><div class="pm-body"><div class="p-cat">${p.cat}</div><h3>${state.lang==='es'?p.nameEs:p.name}</h3><p style="color:var(--gray-500);margin:12px 0">${state.lang==='es'?p.descEs:p.desc}</p>${state.loggedIn?`<div style="font-size:1.5rem;font-weight:800;color:var(--green-dark);margin:16px 0">$${p.price.toFixed(2)}<span style="font-size:0.85rem;font-weight:400;color:var(--gray-400)">${p.unit}</span></div><div style="font-size:0.82rem;color:var(--gray-500);margin-bottom:16px">${T('In stock','En stock')}: ${p.stock}</div><button class="btn btn-primary btn-block" onclick="addToCart(${p.id});closeProductModal()">${T('Add to Order','Agregar')}</button><span class="assurance">${T('No minimum. Free delivery.','Sin mínimo. Entrega gratis.')}</span>`:`<button class="btn btn-primary btn-block" onclick="closeProductModal();showLogin()" style="margin-top:20px">${T('Sign In to See Price','Inicia Sesión para Precio')}</button><span class="assurance">${T('Free account. 30 seconds.','Cuenta gratis. 30 segundos.')}</span>`}</div>`;document.getElementById('product-modal').classList.add('active');}
function closeProductModal(){document.getElementById('product-modal').classList.remove('active');}
function addToCart(id){const p=products.find(x=>x.id===id);if(!p)return;const e=state.cart.find(i=>i.id===id);if(e)e.qty++;else state.cart.push({id:p.id,name:p.name,nameEs:p.nameEs,price:p.price,unit:p.unit,qty:1});updateCartCount();saveCart();openCart();}
function removeFromCart(id){state.cart=state.cart.filter(i=>i.id!==id);updateCartCount();saveCart();renderCart();}
function updateQty(id,d){const i=state.cart.find(x=>x.id===id);if(!i)return;i.qty+=d;if(i.qty<=0){removeFromCart(id);return;}updateCartCount();saveCart();renderCart();}
function updateCartCount(){const c=state.cart.reduce((s,i)=>s+i.qty,0);document.querySelectorAll('.cart-count').forEach(el=>{el.textContent=c;el.style.display=c>0?'flex':'none';});}
function renderCart(){const body=document.getElementById('cart-body'),footer=document.getElementById('cart-footer');if(!body)return;if(!state.cart.length){body.innerHTML=`<div class="cart-empty"><p>${i18n[state.lang]?.['cart.empty']}</p></div>`;footer.style.display='none';return;}footer.style.display='';body.innerHTML=state.cart.map(i=>`<div class="cart-item"><div class="cart-item-img" style="background:var(--green-light);color:var(--green);font-weight:700;font-size:0.75rem">${i.name.substring(0,2).toUpperCase()}</div><div class="cart-item-info"><div class="ci-name">${state.lang==='es'?i.nameEs:i.name}</div><div class="ci-meta">${i.unit}</div><div class="ci-price">$${(i.price*i.qty).toFixed(2)}</div><div class="cart-qty"><button onclick="updateQty(${i.id},-1)">-</button><span>${i.qty}</span><button onclick="updateQty(${i.id},1)">+</button></div><div class="cart-remove" onclick="removeFromCart(${i.id})">${i18n[state.lang]?.['cart.remove']}</div></div></div>`).join('');const sub=state.cart.reduce((s,i)=>s+i.price*i.qty,0);document.getElementById('cart-sub').textContent='$'+sub.toFixed(2);document.getElementById('cart-total').textContent='$'+sub.toFixed(2);}
function openCart(){renderCart();document.getElementById('cart-drawer').classList.add('open');document.getElementById('overlay').classList.add('active');}
function closeCart(){document.getElementById('cart-drawer').classList.remove('open');document.getElementById('overlay').classList.remove('active');}
function placeOrder(){if(!state.cart.length)return;const o={id:'ALM-'+Math.floor(3000+Math.random()*1000),date:new Date().toISOString().split('T')[0],customer:'Taqueria El Sol',items:state.cart.map(i=>({name:i.name,qty:i.qty,price:i.price})),status:'processing',total:state.cart.reduce((s,i)=>s+i.price*i.qty,0)};orders.unshift(o);saveOrders(orders);alert(T(`Order #${o.id} placed! $${o.total.toFixed(2)}. Delivery tomorrow.`,`Pedido #${o.id}! $${o.total.toFixed(2)}. Entrega mañana.`));state.cart=[];saveCart();updateCartCount();closeCart();if(document.getElementById('page-dash-customer')?.classList.contains('active'))renderCustDash();}
function openMobile(){document.getElementById('mobile-menu').classList.add('open');document.getElementById('overlay').classList.add('active');}
function closeMobile(){document.getElementById('mobile-menu').classList.remove('open');document.getElementById('overlay').classList.remove('active');}
function formInit(){renderFormStep();}
function renderFormStep(){const c=document.getElementById('msf-container');if(!c)return;document.getElementById('msf-bar').style.width=(state.formStep*20)+'%';const s={1:()=>`<div class="msf-step"><h3>${T('What type of business are you?','¿Qué tipo de negocio tienes?')}</h3><div class="msf-cards">${['Restaurant','Food Truck','Catering','Grocery / Tienda','Church / Organization','Other'].map(t=>`<button class="msf-card" onclick="state.formData.type='${t}';formNext()">${t}</button>`).join('')}</div></div>`,2:()=>`<div class="msf-step"><h3>${T('Tell us about your business','Cuéntanos sobre tu negocio')}</h3><div class="form-group"><label>${T('Business Name','Nombre del Negocio')}</label><input id="f-biz" type="text" value="${state.formData.biz||''}"></div><div class="form-group"><label>${T('Your Name','Tu Nombre')}</label><input id="f-name" type="text" value="${state.formData.name||''}"></div><div style="display:flex;gap:8px;margin-top:20px"><button class="btn btn-ghost" onclick="formBack()">${T('Back','Atrás')}</button><button class="btn btn-primary" onclick="state.formData.biz=document.getElementById('f-biz').value;state.formData.name=document.getElementById('f-name').value;formNext()">${T('Continue','Continuar')}</button></div></div>`,3:()=>`<div class="msf-step"><h3>${T('What do you need most?','¿Qué necesitas más?')}</h3><div class="msf-checks">${['Dairy & Cheese','Meat & Protein','Fresh Produce','Dry Goods','Supplies'].map(t=>`<label class="msf-check"><input type="checkbox" value="${t}"><span>${t}</span></label>`).join('')}</div><div style="display:flex;gap:8px;margin-top:20px"><button class="btn btn-ghost" onclick="formBack()">${T('Back','Atrás')}</button><button class="btn btn-primary" onclick="state.formData.needs=[...document.querySelectorAll('.msf-check input:checked')].map(i=>i.value);formNext()">${T('Continue','Continuar')}</button></div></div>`,4:()=>`<div class="msf-step"><h3>${T('How can we reach you?','¿Cómo te contactamos?')}</h3><div class="form-group"><label>${T('Email','Correo')}</label><input id="f-email" type="email" value="${state.formData.email||''}"></div><div class="form-group"><label>${T('Phone','Teléfono')}</label><input id="f-phone" type="tel" value="${state.formData.phone||''}"></div><div style="display:flex;gap:8px;margin-top:20px"><button class="btn btn-ghost" onclick="formBack()">${T('Back','Atrás')}</button><button class="btn btn-primary" onclick="state.formData.email=document.getElementById('f-email').value;state.formData.phone=document.getElementById('f-phone').value;formNext()">${T('Get My Custom Quote','Obtener Cotización')}</button></div><span class="assurance">${T('No spam. We call within 24 hours.','Sin spam. Llamamos en 24 horas.')}</span></div>`,5:()=>`<div class="msf-step" style="text-align:center"><div style="width:48px;height:48px;background:var(--green);border-radius:50%;display:flex;align-items:center;justify-content:center;margin:0 auto 16px;color:var(--white);font-size:1.5rem">✓</div><h3>${T('Thank you','Gracias')}, ${state.formData.name||''}!</h3><p style="color:var(--gray-500);margin:12px 0">${T('We\'ll call within 24 hours.','Te llamaremos en 24 horas.')}</p><button class="btn btn-primary" onclick="state.formStep=1;state.formData={};formInit()">${T('Start Over','Empezar de Nuevo')}</button></div>`};c.innerHTML=(s[state.formStep]||s[1])();}
function formNext(){state.formStep++;localStorage.setItem('alamo_form',JSON.stringify(state.formData));renderFormStep();}
function formBack(){state.formStep=Math.max(1,state.formStep-1);renderFormStep();}
let dashTab='overview';
function setDashTab(tab){dashTab=tab;if(state.role==='owner'){renderOwnerSidebar();renderOwnerDash();}else{renderCustTabs();renderCustDash();}}
function renderCustTabs(){const el=document.getElementById('cust-tabs');if(!el)return;el.innerHTML=['overview','shop','orders','invoices','reorder'].map(t=>`<button class="dash-tab${dashTab===t?' active':''}" onclick="setDashTab('${t}')">${{overview:T('Overview','General'),shop:T('Shop','Tienda'),orders:T('Orders','Pedidos'),invoices:T('Invoices','Facturas'),reorder:T('Reorder','Reordenar')}[t]}</button>`).join('');}
function renderCustDash(){const el=document.getElementById('cust-content');if(!el)return;({overview:cO,shop:cS,orders:cR,invoices:cI,reorder:cQ}[dashTab]||cO)(el);}
function cO(el){const my=orders.filter(o=>o.customer==='Taqueria El Sol');el.innerHTML=`<div class="dash-welcome"><h2>${T('Welcome, Taqueria El Sol','Bienvenido, Taqueria El Sol')}</h2></div><div class="stat-cards"><div class="stat-card"><div class="sc-label">${T('Spend','Gasto')}</div><div class="sc-value">$${my.reduce((s,o)=>s+o.total,0).toFixed(0)}</div></div><div class="stat-card"><div class="sc-label">${T('Orders','Pedidos')}</div><div class="sc-value">${my.length}</div></div><div class="stat-card"><div class="sc-label">OTIF</div><div class="sc-value" style="color:var(--green)">98.2%</div></div><div class="stat-card"><div class="sc-label">${T('Cart','Carrito')}</div><div class="sc-value">${state.cart.reduce((s,i)=>s+i.qty,0)}</div><div class="sc-change"><a href="#" onclick="setDashTab('shop');return false" style="color:var(--green)">${T('Shop','Tienda')}</a></div></div></div><div class="dash-grid"><div><div class="dash-panel"><h4>${T('Recent Orders','Pedidos')}</h4>${my.slice(0,4).map(o=>`<div class="d-row"><div><strong>#${o.id}</strong><br><span style="font-size:0.75rem;color:var(--gray-400)">${o.date}</span></div><div style="text-align:right">$${o.total.toFixed(2)}<br><span class="d-status ${statusClass(o.status)}">${statusLabel(o.status)}</span></div></div>`).join('')}<button class="btn btn-primary btn-sm" style="margin-top:12px" onclick="setDashTab('shop')">${T('New Order','Nuevo Pedido')}</button></div></div><div><div class="dash-panel"><h4>${T('Account Health','Salud')}</h4><div style="margin-bottom:8px"><div style="display:flex;justify-content:space-between;font-size:0.82rem"><span>${T('Fill','Surtido')}</span><span style="font-weight:700;color:var(--green)">99.1%</span></div><div class="progress-bar"><div class="fill fill-green" style="width:99.1%"></div></div></div><div style="margin-bottom:8px"><div style="display:flex;justify-content:space-between;font-size:0.82rem"><span>${T('On-Time','A Tiempo')}</span><span style="font-weight:700;color:var(--green)">98.2%</span></div><div class="progress-bar"><div class="fill fill-green" style="width:98.2%"></div></div></div><div><div style="display:flex;justify-content:space-between;font-size:0.82rem"><span>${T('Payment','Pago')}</span><span style="font-weight:700;color:var(--green)">A+</span></div><div class="progress-bar"><div class="fill fill-green" style="width:100%"></div></div></div></div></div></div>`;}
function cS(el){el.innerHTML=`<div class="dash-welcome"><h2>${T('Shop & Order','Ordenar')}</h2></div>${state.cart.length?`<div style="background:var(--green-light);border:1px solid var(--green);border-radius:var(--radius-sm);padding:12px 16px;margin-bottom:20px;display:flex;justify-content:space-between;align-items:center;flex-wrap:wrap;gap:8px"><span><strong>${state.cart.reduce((s,i)=>s+i.qty,0)} ${T('items','art.')}</strong> — $${state.cart.reduce((s,i)=>s+i.price*i.qty,0).toFixed(2)}</span><div style="display:flex;gap:8px"><button class="btn btn-sm btn-outline" onclick="openCart()">${T('Cart','Carrito')}</button><button class="btn btn-sm btn-primary" onclick="placeOrder()">${T('Place Order','Ordenar')}</button></div></div>`:''}<div class="catalog-toolbar"><div class="catalog-search"><svg viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><circle cx="11" cy="11" r="8"/><line x1="21" y1="21" x2="16.65" y2="16.65"/></svg><input placeholder="${T('Search...','Buscar...')}" oninput="state.search=this.value;cS(document.getElementById('cust-content'))"></div><div class="catalog-tabs">${['all','dairy','meat','produce','dry','supplies'].map(c=>`<button class="catalog-tab${state.category===c?' active':''}" onclick="state.category='${c}';cS(document.getElementById('cust-content'))">${i18n[state.lang]?.['catalog.'+c]||c}</button>`).join('')}</div></div><div class="products-grid">${getF().map(p=>`<div class="product-card" onclick="openProductModal(${p.id})"><div class="p-img" style="background:${catColors[p.cat]}15"><div class="p-img-icon" style="color:${catColors[p.cat]}">${p.cat[0].toUpperCase()}</div></div><div class="p-body"><div class="p-cat">${p.cat}</div><div class="p-name">${state.lang==='es'?p.nameEs:p.name}</div><div class="p-foot"><div class="p-price">$${p.price.toFixed(2)}<span class="p-unit">${p.unit}</span></div><button class="p-add" onclick="event.stopPropagation();addToCart(${p.id});cS(document.getElementById('cust-content'))">+</button></div></div></div>`).join('')}</div>`;}
function getF(){let l=products.filter(p=>p.active);if(state.category!=='all')l=l.filter(p=>p.cat===state.category);if(state.search){const q=state.search.toLowerCase();l=l.filter(p=>p.name.toLowerCase().includes(q)||p.nameEs.toLowerCase().includes(q));}return l;}
function cR(el){const my=orders.filter(o=>o.customer==='Taqueria El Sol');el.innerHTML=`<div class="dash-welcome"><h2>${T('Your Orders','Tus Pedidos')}</h2></div><div class="dash-panel"><table class="customer-table"><thead><tr><th>#</th><th>${T('Date','Fecha')}</th><th>${T('Total','Total')}</th><th>${T('Status','Estado')}</th><th>${T('Items','Art.')}</th></tr></thead><tbody>${my.map(o=>`<tr><td><strong>${o.id}</strong></td><td>${o.date}</td><td>$${o.total.toFixed(2)}</td><td><span class="d-status ${statusClass(o.status)}">${statusLabel(o.status)}</span></td><td style="font-size:0.75rem;color:var(--gray-400)">${o.items.map(i=>`${i.qty}x ${i.name}`).join(', ')}</td></tr>`).join('')}</tbody></table></div><button class="btn btn-primary" onclick="setDashTab('shop')" style="margin-top:16px">${T('New Order','Nuevo Pedido')}</button>`;}
function cI(el){el.innerHTML=`<div class="dash-welcome"><h2>${T('Invoices','Facturas')}</h2></div><div class="stat-cards"><div class="stat-card"><div class="sc-label">${T('Outstanding','Pendiente')}</div><div class="sc-value">$1,240</div></div><div class="stat-card"><div class="sc-label">${T('Paid','Pagado')}</div><div class="sc-value" style="color:var(--green)">$7,180</div></div><div class="stat-card"><div class="sc-label">${T('Terms','Términos')}</div><div class="sc-value" style="font-size:1.3rem">Net-15</div></div></div><div class="dash-panel"><table class="customer-table"><thead><tr><th>${T('Invoice','Factura')}</th><th>${T('Amount','Monto')}</th><th>${T('Status','Estado')}</th></tr></thead><tbody><tr><td>INV-4892</td><td>$642.30</td><td><span class="d-status st-processing">${T('Current','Corriente')}</span></td></tr><tr><td>INV-4878</td><td>$418.75</td><td><span class="d-status st-processing">${T('Current','Corriente')}</span></td></tr><tr><td>INV-4845</td><td>$567.50</td><td><span class="d-status st-delivered">${T('Paid','Pagado')}</span></td></tr></tbody></table></div>`;}
function cQ(el){const items=[{n:'Queso Oaxaca',q:10,p:4.25},{n:'Corn Tortillas',q:2,p:18.99},{n:'Pork Butt',q:30,p:2.99},{n:'Chile Guajillo',q:4,p:8.75},{n:'Avocados',q:1,p:42.00},{n:'Tomatoes',q:25,p:1.49},{n:'Cilantro',q:1,p:14.99},{n:'Onions',q:1,p:18.99}];const t=items.reduce((s,i)=>s+i.p*i.q,0);el.innerHTML=`<div class="dash-welcome"><h2>${T('Quick Reorder','Reordenar')}</h2></div><div class="dash-panel"><table class="customer-table"><thead><tr><th>${T('Product','Producto')}</th><th>${T('Qty','Cant')}</th><th>${T('Subtotal','Subtotal')}</th></tr></thead><tbody>${items.map(i=>`<tr><td>${i.n}</td><td>${i.q}</td><td style="font-weight:700">$${(i.p*i.q).toFixed(2)}</td></tr>`).join('')}</tbody><tfoot><tr><td colspan="2" style="text-align:right;font-weight:800">${T('Total','Total')}</td><td style="font-weight:800;color:var(--green-dark)">$${t.toFixed(2)}</td></tr></tfoot></table><div style="display:flex;gap:8px;margin-top:16px;justify-content:flex-end"><button class="btn btn-outline" onclick="setDashTab('shop')">${T('Edit','Editar')}</button><button class="btn btn-primary" onclick="qReorder()">${T('Order Now','Ordenar')}</button></div></div>`;}
function qReorder(){const items=[{name:'Queso Oaxaca',qty:10,price:4.25},{name:'Corn Tortillas',qty:2,price:18.99},{name:'Pork Butt',qty:30,price:2.99},{name:'Chile Guajillo',qty:4,price:8.75},{name:'Avocados',qty:1,price:42.00},{name:'Tomatoes',qty:25,price:1.49},{name:'Cilantro',qty:1,price:14.99},{name:'Onions',qty:1,price:18.99}];const t=items.reduce((s,i)=>s+i.price*i.qty,0);orders.unshift({id:'ALM-'+Math.floor(3000+Math.random()*1000),date:new Date().toISOString().split('T')[0],customer:'Taqueria El Sol',items,status:'processing',total:t});saveOrders(orders);alert(T('Order placed!','Pedido realizado!'));setDashTab('orders');}
function renderOwnerSidebar(){const nav=document.getElementById('os-nav');if(!nav)return;const tabs=[{id:'overview',l:T('Overview','General')},{id:'customers',l:T('Customers','Clientes')},{id:'orders',l:T('Orders','Pedidos')},{id:'inventory',l:T('Products','Productos')},{id:'invoices',l:T('Invoices','Facturas')},{id:'fleet',l:T('Fleet','Flota')}];nav.innerHTML=tabs.map(t=>`<a class="os-link${dashTab===t.id?' active':''}" onclick="setDashTab('${t.id}');closeOwnerSidebar()">${t.l}</a>`).join('');}
function toggleOwnerSidebar(){document.getElementById('owner-sidebar').classList.toggle('open');}
function closeOwnerSidebar(){if(window.innerWidth<=960)document.getElementById('owner-sidebar')?.classList.remove('open');}
function renderOwnerDash(){const el=document.getElementById('owner-body');if(!el)return;({overview:oO,customers:oC,orders:oR,inventory:oP,invoices:oI,fleet:oF}[dashTab]||oO)(el);}
function oO(el){el.innerHTML=`<div class="dash-welcome"><h2>${T('Operations','Operaciones')}</h2></div><div class="stat-cards"><div class="stat-card"><div class="sc-label">${T('Revenue','Ingresos')}</div><div class="sc-value">$978,436</div><div class="sc-change sc-up">+8.2%</div></div><div class="stat-card"><div class="sc-label">${T('External','Externos')}</div><div class="sc-value">$81,373</div><div class="sc-change sc-neutral">8.3%</div></div><div class="stat-card"><div class="sc-label">${T('Products','Productos')}</div><div class="sc-value">${products.filter(p=>p.active).length}</div></div><div class="stat-card"><div class="sc-label">${T('Pending','Pendientes')}</div><div class="sc-value">${orders.filter(o=>o.status!=='delivered').length}</div></div></div><div class="dash-grid"><div><div class="dash-panel"><h4>${T('Recent Orders','Pedidos')}</h4>${orders.slice(0,5).map(o=>`<div class="d-row"><div><strong>#${o.id}</strong><br><span style="font-size:0.75rem;color:var(--gray-400)">${o.date} — ${o.customer}</span></div><div style="text-align:right">$${o.total.toFixed(2)}<br><span class="d-status ${statusClass(o.status)}">${statusLabel(o.status)}</span></div></div>`).join('')}</div></div><div><div class="dash-panel"><h4>${T('Revenue Split','Desglose')}</h4><div style="margin-bottom:8px"><div style="display:flex;justify-content:space-between;font-size:0.82rem"><span>${T('Internal','Interno')}</span><span style="font-weight:700">56.1%</span></div><div class="progress-bar"><div class="fill fill-green" style="width:56.1%"></div></div></div><div style="margin-bottom:8px"><div style="display:flex;justify-content:space-between;font-size:0.82rem"><span>TBD</span><span style="font-weight:700">31.3%</span></div><div class="progress-bar"><div class="fill fill-gold" style="width:31.3%"></div></div></div><div><div style="display:flex;justify-content:space-between;font-size:0.82rem"><span>${T('External','Externo')}</span><span style="font-weight:700">8.3%</span></div><div class="progress-bar"><div class="fill fill-red" style="width:8.3%"></div></div></div></div><div class="dash-panel"><h4>${T('Alerts','Alertas')}</h4>${products.filter(p=>p.stock<50&&p.active).map(p=>`<div class="d-row" style="color:var(--gold)"><div>${T('Low Stock','Stock Bajo')} — ${p.name}</div><div>${p.stock}</div></div>`).join('')}<div class="d-row" style="color:var(--red)"><div>${T('AR Past Due','CxC Vencida')} — Santa Maria</div><div>$14,715</div></div></div></div></div>`;}
function oC(el){el.innerHTML=`<div class="dash-welcome"><h2>${T('Customers','Clientes')}</h2></div><div class="dash-panel"><table class="customer-table"><thead><tr><th>${T('Account','Cuenta')}</th><th>${T('Revenue','Ingresos')}</th><th>%</th><th>${T('Type','Tipo')}</th><th>${T('Health','Salud')}</th></tr></thead><tbody><tr><td>Hacienda McDonough</td><td>$115,011</td><td>11.8%</td><td>Internal</td><td><span class="health-dot dot-green"></span></td></tr><tr><td>The Grove Taqueria</td><td>$76,854</td><td>7.9%</td><td>Internal</td><td><span class="health-dot dot-green"></span></td></tr><tr><td>Zokalo Collage Park</td><td>$76,787</td><td>7.8%</td><td>TBD</td><td><span class="health-dot dot-yellow"></span></td></tr><tr><td>Los Mariachis</td><td>$61,966</td><td>6.3%</td><td>External</td><td><span class="health-dot dot-green"></span></td></tr><tr><td>Taqueria El Sol</td><td>$8,420</td><td>0.9%</td><td>External</td><td><span class="health-dot dot-green"></span></td></tr><tr><td>Santa Maria</td><td>$14,715</td><td>1.5%</td><td>External</td><td><span class="health-dot dot-red"></span></td></tr></tbody></table></div>`;}
function oR(el){el.innerHTML=`<div class="dash-welcome"><h2>${T('All Orders','Pedidos')}</h2></div><div class="dash-panel"><table class="customer-table"><thead><tr><th>#</th><th>${T('Date','Fecha')}</th><th>${T('Customer','Cliente')}</th><th>${T('Total','Total')}</th><th>${T('Status','Estado')}</th><th></th></tr></thead><tbody>${orders.map(o=>`<tr><td><strong>${o.id}</strong></td><td>${o.date}</td><td>${o.customer}</td><td>$${o.total.toFixed(2)}</td><td><span class="d-status ${statusClass(o.status)}">${statusLabel(o.status)}</span></td><td>${o.status!=='delivered'?`<select onchange="updOS('${o.id}',this.value)" style="font-size:0.75rem;padding:4px;border:1px solid var(--gray-300);border-radius:4px"><option value="processing" ${o.status==='processing'?'selected':''}>${T('Processing','Procesando')}</option><option value="transit" ${o.status==='transit'?'selected':''}>${T('In Transit','En Tránsito')}</option><option value="delivered" ${o.status==='delivered'?'selected':''}>${T('Delivered','Entregado')}</option></select>`:''}</td></tr>`).join('')}</tbody></table></div>`;}
function updOS(id,s){const o=orders.find(x=>x.id===id);if(o){o.status=s;saveOrders(orders);renderOwnerDash();}}
function oP(el){el.innerHTML=`<div class="dash-welcome"><h2>${T('Products','Productos')}</h2><p>${products.filter(p=>p.active).length} ${T('active','activos')} / ${products.length} ${T('total','total')}</p></div><div style="margin-bottom:16px;display:flex;gap:10px"><button class="btn btn-primary btn-sm" onclick="showAP()">${T('+ Add','+ Agregar')}</button><button class="btn btn-outline btn-sm" onclick="if(confirm('Reset?')){products=[...defaultProducts];saveProducts(products);oP(document.getElementById('owner-body'))}">${T('Reset','Restablecer')}</button></div><div id="ap-area"></div><div class="dash-panel"><table class="customer-table"><thead><tr><th>${T('Product','Producto')}</th><th>${T('Cat','Cat')}</th><th>${T('Price','Precio')}</th><th>${T('Stock','Stock')}</th><th>${T('Status','Estado')}</th><th></th></tr></thead><tbody>${products.map(p=>`<tr style="${!p.active?'opacity:0.5':''}"><td><strong>${p.name}</strong></td><td>${p.cat}</td><td><input type="number" value="${p.price}" step="0.01" style="width:70px;padding:4px;border:1px solid var(--gray-300);border-radius:4px;font-size:0.82rem" onchange="products.find(x=>x.id===${p.id}).price=parseFloat(this.value);saveProducts(products)"></td><td><input type="number" value="${p.stock}" style="width:60px;padding:4px;border:1px solid var(--gray-300);border-radius:4px;font-size:0.82rem" onchange="products.find(x=>x.id===${p.id}).stock=parseInt(this.value);saveProducts(products)"></td><td>${p.active?`<span class="d-status st-delivered">${T('On','Activo')}</span>`:`<span class="d-status" style="background:var(--gray-200);color:var(--gray-500)">Off</span>`}</td><td><button class="btn btn-sm ${p.active?'btn-outline':'btn-primary'}" onclick="products.find(x=>x.id===${p.id}).active=!products.find(x=>x.id===${p.id}).active;saveProducts(products);oP(document.getElementById('owner-body'))">${p.active?T('Off','Desact.'):T('On','Act.')}</button> <button class="btn btn-sm" style="color:var(--red)" onclick="if(confirm('Delete?')){products=products.filter(x=>x.id!==${p.id});saveProducts(products);oP(document.getElementById('owner-body'))}">X</button></td></tr>`).join('')}</tbody></table></div>`;}
function showAP(){document.getElementById('ap-area').innerHTML=`<div class="dash-panel" style="margin-bottom:16px"><h4>${T('Add Product','Agregar')}</h4><div style="display:grid;grid-template-columns:1fr 1fr 1fr;gap:12px;margin-top:12px"><div class="form-group"><label>Name</label><input id="np-n"></div><div class="form-group"><label>Name ES</label><input id="np-e"></div><div class="form-group"><label>Cat</label><select id="np-c"><option value="dairy">Dairy</option><option value="meat">Meat</option><option value="produce">Produce</option><option value="dry">Dry</option><option value="supplies">Supplies</option></select></div><div class="form-group"><label>Price</label><input id="np-p" type="number" step="0.01"></div><div class="form-group"><label>Unit</label><input id="np-u" placeholder="/lb"></div><div class="form-group"><label>Stock</label><input id="np-s" type="number" value="100"></div></div><div style="display:flex;gap:8px;margin-top:8px"><button class="btn btn-primary btn-sm" onclick="doAP()">Save</button><button class="btn btn-outline btn-sm" onclick="document.getElementById('ap-area').innerHTML=''">Cancel</button></div></div>`;}
function doAP(){const n=document.getElementById('np-n').value.trim();if(!n)return;products.unshift({id:Date.now(),name:n,nameEs:document.getElementById('np-e').value.trim()||n,cat:document.getElementById('np-c').value,price:parseFloat(document.getElementById('np-p').value)||0,unit:document.getElementById('np-u').value||'/lb',badge:'new',active:true,stock:parseInt(document.getElementById('np-s').value)||100,desc:n,descEs:document.getElementById('np-e').value.trim()||n});saveProducts(products);oP(document.getElementById('owner-body'));}
function oI(el){el.innerHTML=`<div class="dash-welcome"><h2>${T('Accounts Receivable','CxC')}</h2></div><div class="stat-cards"><div class="stat-card"><div class="sc-label">${T('Total','Total')}</div><div class="sc-value">$42,180</div></div><div class="stat-card"><div class="sc-label">${T('Current','Corriente')}</div><div class="sc-value" style="color:var(--green)">$28,420</div></div><div class="stat-card"><div class="sc-label">${T('Aging','Antiguo')}</div><div class="sc-value" style="color:var(--gold)">$5,360</div></div><div class="stat-card"><div class="sc-label">${T('Past Due','Vencido')}</div><div class="sc-value" style="color:var(--red)">$8,400</div></div></div><div class="dash-panel"><table class="customer-table"><thead><tr><th>#</th><th>${T('Account','Cuenta')}</th><th>${T('Amount','Monto')}</th><th>${T('Status','Estado')}</th></tr></thead><tbody><tr><td>INV-4821</td><td>Santa Maria</td><td>$14,715</td><td><span class="d-status" style="background:var(--red-light);color:var(--red)">${T('Past Due','Vencido')}</span></td></tr><tr><td>INV-4856</td><td>Zokalo</td><td>$8,240</td><td><span class="d-status st-transit">${T('Aging','Antiguo')}</span></td></tr><tr><td>INV-4872</td><td>Los Mariachis</td><td>$5,360</td><td><span class="d-status st-processing">${T('Current','Corriente')}</span></td></tr><tr><td>INV-4901</td><td>Botanico</td><td>$3,420</td><td><span class="d-status st-delivered">${T('Paid','Pagado')}</span></td></tr></tbody></table></div>`;}
function oF(el){el.innerHTML=`<div class="dash-welcome"><h2>${T('Fleet','Flota')}</h2></div><div class="stat-cards"><div class="stat-card"><div class="sc-label">${T('Trucks','Camiones')}</div><div class="sc-value">2/2</div></div><div class="stat-card"><div class="sc-label">${T('Deliveries','Entregas')}/wk</div><div class="sc-value">38</div></div><div class="stat-card"><div class="sc-label">OTIF</div><div class="sc-value">96.4%</div></div><div class="stat-card"><div class="sc-label">${T('Fill','Surtido')}</div><div class="sc-value">98.7%</div></div></div><div class="dash-panel"><table class="customer-table"><thead><tr><th>${T('Vehicle','Vehículo')}</th><th>${T('Type','Tipo')}</th><th>${T('Driver','Conductor')}</th><th>${T('Status','Estado')}</th></tr></thead><tbody><tr><td>Truck A</td><td>Reefer</td><td>Carlos M.</td><td><span class="health-dot dot-green"></span>${T('Active','Activo')}</td></tr><tr><td>Truck B</td><td>Box</td><td>Miguel R.</td><td><span class="health-dot dot-yellow"></span>${T('Service','Servicio')}</td></tr></tbody></table></div>`;}
